scwin.setInit = function () {
  lc_taxnClsCd.addItem("선택", "", null, 0);
  lc_taxnClsCd.setSelectedIndex(1);
  ds_comCode.setJSON(dlt_commonCodeSD070.getAllJSON());
  var fn_tmpDeptFilter = function (cellData, tmpParam, rowIdx) {
    if (cellData == "20" || cellData == "30" || cellData == "40" || cellData == "50" || cellData == "60" || cellData == "70" || cellData == "90" || cellData == "95") {
      return true;
    }
    return false;
  };
  dlt_commonCodeFM018.setColumnFilter({
    type: 'func',
    colIndex: 'cd',
    key: fn_tmpDeptFilter,
    condition: 'and'
  });
  lc_reqPayMthdCd.addItem("선택", "", null, 0);
  lc_reqPayMthdCd.setSelectedIndex(0);
};
scwin.setInit2 = function () {
  lc_pchsItemCd.addItem("전체", "", null, 0);
  lc_pchsItemCd.setSelectedIndex(0);
};
//---------------------------------------------------------
// 사용자 함수
