scwin.f_SetDefaultData = function () {
  lc_pchsItemCd.setSelectedIndex(0); // 매입항목
  ed_pchsIntendDtSt.setValue(scwin.vQryStDt); // 매입예정일자시작
  ed_pchsIntendDtEnd.setValue(scwin.vQryEndDt); // 매입예정일자종료
  lc_recptYn.setSelectedIndex(0); // 접수구분
  ed_slipDt.setValue(scwin.vQryEndDt); // 전표일자
  rd_elecAuthTrgtYn.setValue("0"); // 전자세금계산서(미적용)
  $c.gus.cfEnableObjects($p, [ed_spplyDt, rd_elecAuthTrgtYn]);
  $c.gus.cfDisableObjects($p, [lc_taxnClsCd]);
  ed_drawEmpNo.setValue(scwin.memJson.empNo || ""); // 작성자코드
  txt_drawEmpNm.setValue(scwin.memJson.userNm || ""); // 작성자명
  ed_drawAcctDeptCd.setValue(scwin.memJson.acctDeptCd || ""); // 작성귀속부서코드
  txt_drawAcctDeptNm.setValue(scwin.memJson.acctDeptNm || ""); // 작성귀속부서명

  //국제 물류에서 넘어 온값 Default값 셋팅

  if (scwin.pchsDeptCd != "") {
    ed_pchsDeptCd.setValue(scwin.pchsDeptCd);
    txt_pchsDeptNm.setValue(scwin.pchsDeptNm);
  }
  if (!scwin.pchsIntendDtSt == "") {
    ed_pchsIntendDtSt.setValue(scwin.pchsIntendDtSt);
    ed_pchsIntendDtEnd.setValue(scwin.pchsIntendDtEnd);
  }
  if (scwin.certiNo != "") {
    ed_certiNo.setValue(scwin.certiNo);
  }
  if (scwin.pchsClntNo != "") {
    ed_pchsClntNo.setValue(scwin.pchsClntNo);
    txt_pchsClntNm.setValue(scwin.pchsClntNm);
    scwin.f_RetrieveCertiList(); //바로 조회  	 
  } else {
    // $c.gus.cfSetIMEModeActiveObjects([txt_pchsClntNm, txt_pchsDeptNm, txt_admitPicNm, txt_adjmDept, txt_summary, txt_drawEmpNm, txt_drawAcctDeptNm]);  // IME 한글입력
    $c.gus.cfDisableObjects($p, [ed_adjmDept, txt_adjmDept, img_PopUp4, ed_slipDt, lc_evidKndClsCd, lc_taxnClsCd, txt_summary, ed_drawEmpNo, txt_drawEmpNm, img_PopUp5, ed_drawAcctDeptCd, txt_drawAcctDeptNm, img_PopUp6, ed_spplyDt, rd_elecAuthTrgtYn]);
    ed_pchsClntNo.focus();
    $c.gus.cfDisableBtnOnly($p, [btn_save]);
  }
};
scwin.f_RetrieveCertiList = async function () {
  // 검색조건 필수 입력 체크, 동일 날짜 포함 여부 체크
  var validFlag = await $c.gus.cfValidate($p, [ed_pchsClntNo, ed_pchsIntendDtSt, ed_pchsIntendDtEnd]);
  // debugger;
  if (!validFlag) {
    return;
  }
  validFlag = await $c.gus.cfIsAfterDate($p, ed_pchsIntendDtSt.getValue(), ed_pchsIntendDtEnd.getValue());
  if (!validFlag) {
    $c.gus.cfAlertMsg($p, "조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
    ed_pchsIntendDtSt.focus();
    return;
  }
  if (validFlag) {
    pchsClntNo = ed_pchsClntNo.getValue();
    ds_certiList.removeAll();
    ds_purchaseCerti.removeAll();
    ds_searchCertiList.set("pchsClntNo", pchsClntNo);
    $c.sbm.execute($p, sbm_searchCertiList);
  }
};
scwin.f_PchsDataClear = function () {
  // 전표일자, 공급일자 구하기 위한 변수
  var inputDate = ed_pchsIntendDtEnd.getValue();
  var year = inputDate.substring(0, 4);
  var month = inputDate.substring(4, 6);
  ed_adjmDept.setValue(""); // 정산부서코드
  txt_adjmDept.setValue(""); // 정산부서명
  lay_nmCmpy.setValue(""); // 상호
  lay_busiNo.setValue(""); // 사업자번호

  ed_slipDt.setValue(year + month + $c.date.getLastDateOfMonth($p, year + month)); // 전표일자

  lc_evidKndClsCd.setValue("10"); // 증빙구분(세금계산서)
  lc_taxnClsCd.setValue("01"); // 과세구분(과세)
  txt_summary.setValue(""); // 적요
  rd_elecAuthTrgtYn.setValue("0"); // 전자세금계산서(미적용)
  $c.gus.cfEnableObjects($p, [ed_spplyDt, rd_elecAuthTrgtYn]);
  $c.gus.cfDisableObjects($p, [lc_taxnClsCd]);
  ed_drawEmpNo.setValue(scwin.memJson.empNo);
  txt_drawEmpNm.setValue(scwin.memJson.userNm);
  ed_drawAcctDeptCd.setValue(scwin.memJson.acctDeptCd);
  txt_drawAcctDeptNm.setValue(scwin.memJson.acctDeptNm);
  ed_spplyAmt.setValue(""); // 공급금액
  ed_vat.setValue(""); // 부가세
};
scwin.f_RetrieveClntInfo = async function (row) {
  var condition = "?";
  condition += "pchsClntNo=" + ds_certiList.getCellData(row, "pchsClntNo");
  sbm_searchClntInfo.action = "/ds.fs.adjm.pchsadjmdcsn.RetrieveClntInfoCMD.do" + condition;
  await $c.sbm.execute($p, sbm_searchClntInfo);
  if (ds_clntInfo.getTotalRow() > 0) {
    lay_nmCmpy.setValue(ds_clntInfo.getCellData(0, "nmCmpy")); // 상호
    lay_busiNo.setValue(ds_clntInfo.getCellData(0, "busiNo")); // 사업자번호
  }
};
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
  // 선언부
  var rtnList = new Array(); // 공통POP-UP -> 요청화면 
  var pWhere = "";
  var pWtitleSearch = "";
  switch (disGubun) {
    case 1:
      // 매입거래처 팝업			
      udc_clnt.setSelectId("retrieveClntList");
      udc_clnt.ilCommonPopUp(scwin.udc_clnt_callbackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      break;
    case 2:
      // 매입부서 팝업			
      udc_dept.setSelectId("retrieveLobranInfo");
      udc_dept.ilCommonPopUp(scwin.udc_dept_callbackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      break;
    case 3:
      // 승인담당자 팝업		
      udc_admitPic.setSelectId("retrieveEmpInfo");
      udc_admitPic.ilCommonPopUp(scwin.udc_admitPic_callbackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      break;
    case 4:
      // 정산부서 팝업	
      udc_dept2.setSelectId("retrieveLobranInfo");
      udc_dept2.ilCommonPopUp(scwin.udc_dept2_callbackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      break;
    case 5:
      // 작성자 팝업		
      udc_emp2.setSelectId("retrieveEmpInfo");
      udc_emp2.ilCommonPopUp(scwin.udc_emp2_callbackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      break;
    case 6:
      // 작성귀속부서 팝업
      udc_AcctDept.setSelectId("retrieveAcctDeptCdInfo");
      udc_AcctDept.ilCommonPopUp(scwin.udc_AcctDept_callbackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      break;
    default:
      break;
  }
};
