scwin.sbm_searchCertiList_submitdone = async function () {
  rowCnt = ds_certiList.getTotalRow();
  // 총 조회건수 표시
  ed_totalRow.setValue(rowCnt);
  scwin.f_PchsDataClear();
  if (rowCnt == 0) {
    $c.gus.cfDisableBtnOnly($p, [btn_save]);
    $c.gus.cfDisableObjects($p, [ed_adjmDept, txt_adjmDept, img_PopUp4, ed_slipDt, lc_evidKndClsCd, lc_taxnClsCd, txt_summary, ed_drawEmpNo, txt_drawEmpNm, img_PopUp5, ed_drawAcctDeptCd, txt_drawAcctDeptNm, img_PopUp6, ed_spplyDt, rd_elecAuthTrgtYn]);
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_003); // 해당되는 자료가 존재하지 않습니다
    ds_purchaseCerti.removeAll();
  } else {
    $c.gus.cfEnableBtnOnly($p, [btn_save]);
    $c.gus.cfEnableObjects($p, [ed_adjmDept, txt_adjmDept, img_PopUp4, ed_slipDt, lc_evidKndClsCd, lc_taxnClsCd, txt_summary, ed_drawEmpNo, txt_drawEmpNm, img_PopUp5, ed_drawAcctDeptCd, txt_drawAcctDeptNm, img_PopUp6, ed_spplyDt, rd_elecAuthTrgtYn]);
    for (var i = 0; i < ds_certiList.getTotalRow(); i++) {
      scwin.loopCnt = i;
      await scwin.f_RetrieveClntInfo(i); // 매입증빙(상호,사업자번호) 조회
      idx = ds_purchaseCerti.insertRow();
      ds_purchaseCerti.setCellData(idx, "chk", ""); //거래명세서 번호
      ds_purchaseCerti.setCellData(idx, "adjmDept", ds_certiList.getCellData(i, "pchsDeptCd")); //정산부서
      ds_purchaseCerti.setCellData(idx, "slipDt", scwin.vQryEndDt);
      if (ds_certiList.getCellData(i, "vat") == 0) {
        ds_purchaseCerti.setCellData(idx, "evidKndClsCd", "20");
        ds_purchaseCerti.setCellData(idx, "taxnClsCd", "02");
      } else {
        ds_purchaseCerti.setCellData(idx, "evidKndClsCd", "10");
        ds_purchaseCerti.setCellData(idx, "taxnClsCd", "01");
      }
      ds_purchaseCerti.setCellData(idx, "summary", ds_certiList.getCellData(i, "rmk")); //적요
      ds_purchaseCerti.setCellData(idx, "pchsClntNo", ds_certiList.getCellData(i, "pchsClntNo")); //매입거래처
      if (scwin.partner == "P") {
        ds_purchaseCerti.setCellData(idx, "evidKndClsCd", "20");
        ds_purchaseCerti.setCellData(idx, "taxnClsCd", "03");
      }
      if (scwin.inuChk == "1") {
        ds_purchaseCerti.setCellData(idx, "evidKndClsCd", "00");
      }
      ds_purchaseCerti.setCellData(idx, "drawEmpNo", scwin.memJson.empNo); // 작성자코드
      ds_purchaseCerti.setCellData(idx, "drawAcctDeptCd", scwin.memJson.acctDeptCd); // 작성귀속부서코드

      ds_purchaseCerti.setCellData(idx, "busiNo", lay_busiNo.getValue()); // 사업자번호
      ds_purchaseCerti.setCellData(idx, "spplyDt", ds_certiList.getCellData(i, "pchsIntendDt")); //공급일자

      ds_purchaseCerti.setCellData(idx, "spplyAmt", ds_certiList.getCellData(i, "spplyAmt")); // 공급금액
      ds_purchaseCerti.setCellData(idx, "vat", ds_certiList.getCellData(i, "vat")); // 부가세

      ds_purchaseCerti.setCellData(idx, "elecAuthTrgtYn", 0);
    }
    gr_purchaseCerti.setFocusedCell(0, 0);
  }
  ed_totalRow2.setValue(ds_purchaseCerti.getTotalRow());
  $c.gus.cfDisableObjects($p, [lc_taxnClsCd]);
};
